/**
 * Storage slot that determines where a credential lives on-device.
 *
 * A device can hold one primary credential and up to 15 managed (child)
 * credentials per namespace (Primary / Sandbox), supporting up to 32
 * credentials total. Managed indices run from 0 to 14 inclusive.
 */
sealed class CredentialSlot {
    /**
     * The user's own credential.
     */
    object Primary : CredentialSlot()

    /**
     * A managed (child) credential at a given index (0..14, up to 15 slots).
     */
    data class Managed(
        val `index`: kotlin.UByte,
    ) : CredentialSlot() {
        companion object
    }

    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeCredentialSlot : FfiConverterRustBuffer<CredentialSlot> {
    override fun read(buf: ByteBuffer): CredentialSlot {
        return when (buf.getInt()) {
            1 -> CredentialSlot.Primary
            2 ->
                CredentialSlot.Managed(
                    FfiConverterUByte.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: CredentialSlot) =
        when (value) {
            is CredentialSlot.Primary -> {
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                (
                    4UL
                )
            }
            is CredentialSlot.Managed -> {
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                (
                    4UL +
                        FfiConverterUByte.allocationSize(value.`index`)
                )
            }
        }

    override fun write(
        value: CredentialSlot,
        buf: ByteBuffer,
    ) {
        when (value) {
            is CredentialSlot.Primary -> {
                buf.putInt(1)
                Unit
            }
            is CredentialSlot.Managed -> {
                buf.putInt(2)
                FfiConverterUByte.write(value.`index`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}

